using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // ── CalculateTotal: inline DataRow cases ──

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 3, 0.0, 30.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 4, 0.08, 110.16, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero unit price")]
    [DataRow(10.00, 0, 0.10, 0.00, DisplayName = "Zero quantity")]
    [DataRow(10.00, 1, 1.0, 20.00, DisplayName = "100% tax")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── CalculateTotal: invalid-input guard clauses ──

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));

        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeUnitPrice_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.1m));

        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below zero")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_Throws(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // ── ApplyDiscount: DynamicData with ValueTuples ──

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
        (0m, 50m, 0m),
        (99.99m, 50m, 49.995m),
    ];

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Discount below zero")]
    [DataRow(101.0, DisplayName = "Discount above 100")]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // ── FormatPrice ──

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default dollar")]
    [DataRow(5.10, "€", "€5.10", DisplayName = "Euro symbol")]
    [DataRow(1000.00, "£", "£1000.00", DisplayName = "Pound, large value")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    public void FormatPrice_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

